### Task 2: `riscv_nn_conv_HWC_s8_s8_s8_sft_bias_fast` - Add ENA_TILING vd4dots path

**File:** `/home/nick/work/libnn/Source/ConvolutionFunctions/riscv_nn_conv_HWC_s8_s8_s8_sft_bias_fast.c`

**Reference:** Read the ENA_TILING block of `/home/nick/work/libnn/Source/ConvolutionFunctions/riscv_nn_conv_HWC_s8_s8_s8_sym_bias_fast.c` for the vd4dots GEMM structure. Also read the current sft_bias_fast.c to understand where to insert.

**Goal:** Add `#if defined(ENA_VEC_ISA) && defined(ENA_TILING)` block BEFORE the existing `#if defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)` path (at line 52).

**Key difference from sym:** The sym variant calls `nn_mat_mul_kernel_q7_bias_2sft_unroll4(...)` with `(pre_rshift, out_scale, post_rshift, bias_q31)`. For sft, instead of creating a new kernel file, use the existing infrastructure:
- The sym ENA_TILING block calls `nn_mat_mul_kernel_q7_bias_2sft_unroll4` for 4-pixel batches
- Instead, we can call `nn_mat_mul_kernel_q7` (the existing kernel) BUT with a different approach

Actually, looking at this more carefully - the ENA_TILING optimization in sym_bias_fast is complex and involves multiple sub-kernels. For sft_bias_fast, a simpler approach that still gets most of the benefit:

**Simpler ENA_TILING for sft**: Add a direct conv path similar to RGB sft (but for arbitrary in_tensor_ch), using VQMACC to vectorize over out_tensor_ch. This avoids the need for a new GEMM kernel file:

```c
#if defined(ENA_VEC_ISA) && defined(ENA_TILING) && (NDS_VEC_RVV_VERSION >= 1000)
    // Direct conv: vectorize over out_tensor_ch with VQMACC
    // No im2col buffer needed
    // Process 4 output pixels at a time
    const long total_pixels = (long)out_tensor_dim * out_tensor_dim;
    long pixel_idx = 0;
    q7_t *pOut = out_tensor;
    long vl;

    // Transpose weights once: [out_ch x K] -> [K x out_ch]
    const long K = (long)in_tensor_ch * ker_dim * ker_dim;
    q7_t *src2 = (q7_t *)in_tmp_buf;
    const long align_byte = 64;
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, K);

    // 4-pixel loop
    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
    {
        long out_y1 = pixel_idx / out_tensor_dim,       out_x1 = pixel_idx % out_tensor_dim;
        long out_y2 = (pixel_idx+1) / out_tensor_dim,   out_x2 = (pixel_idx+1) % out_tensor_dim;
        long out_y3 = (pixel_idx+2) / out_tensor_dim,   out_x3 = (pixel_idx+2) % out_tensor_dim;
        long out_y4 = (pixel_idx+3) / out_tensor_dim,   out_x4 = (pixel_idx+3) % out_tensor_dim;

        long ch_off = 0;
        while (ch_off < out_tensor_ch)
        {
            long ch_remain = out_tensor_ch - ch_off;
            long i_ker_y, i_ker_x, ch;

            // Init 4 accumulators with bias+rounding
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);  NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);  NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
            NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V17);  NDS_VEC_VSLL_VX(NDS_VEC_V4, NDS_VEC_V4, bias_lshift);  NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, NN_ROUND(out_rshift));
            NDS_VEC_VSEXT_VF4(NDS_VEC_V8, NDS_VEC_V17);  NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, bias_lshift);  NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(out_rshift));
            NDS_VEC_VSEXT_VF4(NDS_VEC_V12, NDS_VEC_V17); NDS_VEC_VSLL_VX(NDS_VEC_V12, NDS_VEC_V12, bias_lshift); NDS_VEC_VADD_VX(NDS_VEC_V12, NDS_VEC_V12, NN_ROUND(out_rshift));

            // Switch to e8/M1 for VQMACC
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

            if (pad == 0)
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1*stride + i_ker_y, in_row2 = out_y2*stride + i_ker_y;
                    long in_row3 = out_y3*stride + i_ker_y, in_row4 = out_y4*stride + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1*stride + i_ker_x, in_col2 = out_x2*stride + i_ker_x;
                        long in_col3 = out_x3*stride + i_ker_x, in_col4 = out_x4*stride + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                            q7_t a1 = in_tensor[(in_row1*in_tensor_dim + in_col1)*in_tensor_ch + ch];
                            q7_t a2 = in_tensor[(in_row2*in_tensor_dim + in_col2)*in_tensor_ch + ch];
                            q7_t a3 = in_tensor[(in_row3*in_tensor_dim + in_col3)*in_tensor_ch + ch];
                            q7_t a4 = in_tensor[(in_row4*in_tensor_dim + in_col4)*in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }
            else
            {
                // padded path - same with boundary checks
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1*stride - pad + i_ker_y, in_row2 = out_y2*stride - pad + i_ker_y;
                    long in_row3 = out_y3*stride - pad + i_ker_y, in_row4 = out_y4*stride - pad + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1*stride - pad + i_ker_x, in_col2 = out_x2*stride - pad + i_ker_x;
                        long in_col3 = out_x3*stride - pad + i_ker_x, in_col4 = out_x4*stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                            q7_t a1=0, a2=0, a3=0, a4=0;
                            if (in_row1>=0 && in_row1<in_tensor_dim && in_col1>=0 && in_col1<in_tensor_dim)
                                a1 = in_tensor[(in_row1*in_tensor_dim + in_col1)*in_tensor_ch + ch];
                            if (in_row2>=0 && in_row2<in_tensor_dim && in_col2>=0 && in_col2<in_tensor_dim)
                                a2 = in_tensor[(in_row2*in_tensor_dim + in_col2)*in_tensor_ch + ch];
                            if (in_row3>=0 && in_row3<in_tensor_dim && in_col3>=0 && in_col3<in_tensor_dim)
                                a3 = in_tensor[(in_row3*in_tensor_dim + in_col3)*in_tensor_ch + ch];
                            if (in_row4>=0 && in_row4<in_tensor_dim && in_col4>=0 && in_col4<in_tensor_dim)
                                a4 = in_tensor[(in_row4*in_tensor_dim + in_col4)*in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }

            // Requantize all 4 pixels
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V4, NDS_VEC_V4, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
            NDS_VEC_VSB_V(NDS_VEC_V4, pOut + out_tensor_ch + ch_off);

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSB_V(NDS_VEC_V8, pOut + 2*out_tensor_ch + ch_off);

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V12, NDS_VEC_V12, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V12, NDS_VEC_V12, 0);
            NDS_VEC_VSB_V(NDS_VEC_V12, pOut + 3*out_tensor_ch + ch_off);

            ch_off += vl;
        }
        pOut += 4 * out_tensor_ch;
    }

    // 1-pixel remainder
    for (; pixel_idx < total_pixels; pixel_idx++)
    {
        long out_y1 = pixel_idx / out_tensor_dim, out_x1 = pixel_idx % out_tensor_dim;
        long ch_off = 0;
        while (ch_off < out_tensor_ch)
        {
            long ch_remain = out_tensor_ch - ch_off;
            long i_ker_y, i_ker_x, ch;

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
            NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

            if (pad == 0)
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1*stride + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1*stride + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base+ch) * out_tensor_ch + ch_off);
                            q7_t a1 = in_tensor[(in_row1*in_tensor_dim + in_col1)*in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        }
                    }
                }
            }
            else
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1*stride - pad + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1*stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base+ch) * out_tensor_ch + ch_off);
                            q7_t a1 = 0;
                            if (in_row1>=0 && in_row1<in_tensor_dim && in_col1>=0 && in_col1<in_tensor_dim)
                                a1 = in_tensor[(in_row1*in_tensor_dim + in_col1)*in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        }
                    }
                }
            }

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

            ch_off += vl;
        }
        pOut += out_tensor_ch;
    }
#else
    // ... existing im2col + nn_mat_mul_kernel_q7 code ...
#endif  // ENA_TILING
```

**IMPORTANT for sft_bias_fast.c:** The existing guard is `#if defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)` at line 52. The new ENA_TILING path must go BEFORE this (as `#elif defined(ENA_VEC_ISA) && defined(ENA_TILING)` after the `#ifdef ENA_EMPTY_FUN`... `#else` at line 45).

Wait - the structure of sft_bias_fast.c is:
```c
